public int minTotalDistance(int[][] grid) {
    int m = grid.length, n = grid[0].length;
    List<Integer> rows = new ArrayList<>(), cols = new ArrayList<>();
    for (int i = 0; i < m; i++)
        for (int j = 0; j < n; j++)
            if (grid[i][j] == 1) { rows.add(i); cols.add(j); }
    Collections.sort(cols);
    return minDist(rows) + minDist(cols);
}

private int minDist(List<Integer> points) {
    int dist = 0, lo = 0, hi = points.size() - 1;
    while (lo < hi) dist += points.get(hi--) - points.get(lo++);
    return dist;
}

