def minTotalDistance(grid: list[list[int]]) -> int:
    rows: list[int] = []
    cols: list[int] = []
    for i, row in enumerate(grid):
        for j, val in enumerate(row):
            if val == 1:
                rows.append(i)  # already sorted
                cols.append(j)
    cols.sort()

    def min_dist(points: list[int]) -> int:
        dist = 0
        lo, hi = 0, len(points) - 1
        while lo < hi:
            dist += points[hi] - points[lo]
            lo += 1
            hi -= 1
        return dist

    return min_dist(rows) + min_dist(cols)
